package br.com.estacionamento.pagamentos.service;import br.com.estacionamento.pagamentos.model.Pagamento;import br.com.estacionamento.pagamentos.repository.PagamentoRepository;import io.github.resilience4j.retry.annotation.Retry;import org.springframework.stereotype.Service;import java.util.UUID;@Service public class PagamentoService{private final PagamentoRepository repo;public PagamentoService(PagamentoRepository repo){this.repo=repo;}@Retry(name="gatewayPagamento") public Pagamento pagar(Pagamento p){p.status="APROVADO";p.transacaoGateway=UUID.randomUUID().toString();return repo.save(p);}}
